// Pre-generation filter ? runs on the batch of pending comments.
// Tags each with skip / status so a downstream Switch can route:
//   skip === true  -> set Replied = YES, status = skipped, DO NOT generate
//   skip === false -> continue to system-prompt builder + Ollama

const aiPatterns = [
  /\bare (you|u) (an? )?(ai|bot|robot|human|real( person| girl| woman)?)\b/,
  /\bis (this|that|she|it) (an? )?(ai|bot|real|fake|generated)\b/,
  /\b(ai|computer)[- ]?generated\b/,
  /\bai (girl|model|account|influencer)\b/,
  /\bchat ?gpt\b/,
  /\bdeepfake\b/,
  /\bnot (a )?real\b/,
  /\bfake (account|profile|person)\b/,
  /\b(are|r) (you|u) fake\b/,
  /\b(you|u) real\??$/,
  /\bdo (you|u) (even )?exist\b/
];

return $input.all().map(item => {
  const text = (item.json.Text ?? '').toString().toLowerCase();
  const isSkip = aiPatterns.some(rx => rx.test(text));

  return {
    json: {
      ...item.json,
      skip: isSkip,
      status: isSkip ? 'skipped' : 'pending'
    }
  };
});

// Post-generation guard ? Run Once for All Items
return $input.all().map(item => {
  const raw = (item.json.output ?? '').toString();

  // Strip markdown fences, then wrapping quotes (straight AND smart)
  let clean = raw.trim()
    .replace(/^```[\s\S]*?\n?/, '').replace(/```$/, '')
    .replace(/^["'`]+|["'`]+$/g, '')
    .replace(/^[\u201C\u201D\u2018\u2019]+|[\u201C\u201D\u2018\u2019]+$/g, '')
    .trim();

  const banned = [
    /\bas an? (ai|language model|assistant)\b/i,
    /\b(language|ai) model\b/i,
    /\bi (can'?t|cannot|am unable)\b/i,
    /\b(i'?m sorry|i apologize)\b/i,
    /\b(token|api|prompt|json)\b/i,
    /<\/?think>/i, /[{}\[\]]/, /```/
  ];

  const tooLong = clean.length > 280;
  const empty = clean.length === 0;
  const isBad = empty || tooLong || banned.some(rx => rx.test(clean));

  return {
    json: {
      ...item.json,
      replyClean: clean,
      rawReply: raw,
      status: isBad ? 'review' : 'ok'
    }
  };
});

const tokens = $('Tokens').first().json;

const tokenMap = {
  Maeve: tokens.maeveToken,
  Elara: tokens.elaraToken,
  Amara: tokens.amaraToken,
};

const result = {};

for (const item of $input.all()) {
  const {
    Name,
    Personality,
    Birthday,
    Height,
    Country,
    Religion,
    Hair,
    Eyes,
    Skin,
    Breasts,
    Age
  } = item.json;

  result[Name] = {
    Personality,
    Birthday,
    Height,
    Country,
    Religion,
    Hair,
    Eyes,
    Skin,
    Breasts,
    Age,
    Token: tokenMap[Name] ?? null,
  };
}

return [
  {
    json: result
  }
];

// Get the lookup object from the "personality" node
const personalities = $('personality').first().json;

// Add all matching fields to each input item
return $input.all().map(item => ({
  json: {
    ...item.json,
    ...(personalities[item.json.Owner] ?? {})
  }
}));

// Per-user reply gate ? Run Once for All Items
const MAX_PER_USER_PER_DAY = 2;    // replies to one user (per Owner) per day
const COOLDOWN_HOURS       = 6;    // min gap since LAST REPLY to same user
const ONE_PER_RUN          = true; // answer only the newest comment in a burst
const MAX_REPLIES_PER_RUN  = 8;

const rows = $input.all().map(i => i.json);
const keyOf = r => `${r.CommenterId ?? r.CommenterName ?? 'unknown'}|${r.Owner}`;
const yes = v => (v ?? '').toString().trim().toLowerCase() === 'yes';
const no  = v => (v ?? '').toString().trim().toLowerCase() === 'no';

const tComment = r => Date.parse(r.timeISO ?? '') || 0;                       // when they commented
const tReplied = r => Date.parse(r.RepliedAt ?? '') || tComment(r);           // when we replied (fallback: comment time for old rows)

const now = Date.now();
const todayStr = new Date(now).toDateString();

// history from already-handled rows ? keyed on REPLY time
const hist = {};
for (const r of rows) {
  if (!yes(r.Replied)) continue;
  const k = keyOf(r), t = tReplied(r);
  (hist[k] ??= { count: 0, last: 0 });
  if (new Date(t).toDateString() === todayStr) hist[k].count++;
  if (t > hist[k].last) hist[k].last = t;
}

// group pending comments by user
const pending = {};
for (const r of rows) {
  if (!no(r.Replied)) continue;
  (pending[keyOf(r)] ??= []).push(r);
}

const replyItems = [], skipItems = [];
for (const group of Object.values(pending)) {
  const h = hist[keyOf(group[0])] ?? { count: 0, last: 0 };
  const overCap    = h.count >= MAX_PER_USER_PER_DAY;
  const inCooldown = h.last && (now - h.last) < COOLDOWN_HOURS * 3600e3;

  if (overCap || inCooldown) {
    group.forEach(r => skipItems.push({ ...r, action: 'skip',
      skipReason: overCap ? 'daycap' : 'cooldown' }));
    continue;
  }
  const sorted = [...group].sort((a, b) => tComment(b) - tComment(a)); // newest comment first
  const chosen = ONE_PER_RUN ? [sorted[0]] : sorted;
  const rest   = ONE_PER_RUN ? sorted.slice(1) : [];
  chosen.forEach(r => replyItems.push({ ...r, action: 'reply' }));
  rest.forEach(r => skipItems.push({ ...r, action: 'skip', skipReason: 'batched' }));
}

// oldest comments first, then cap per run
replyItems.sort((a, b) => tComment(a) - tComment(b));
const capped = replyItems.slice(0, MAX_REPLIES_PER_RUN);

return [...capped, ...skipItems].map(json => ({ json }));

